#include <OneWire.h>
#include <DallasTemperature.h>
#include <SD.h>
#define OW_PIN 2
#define SSR_PIN 8
#define REFLUX_V 6
#define DIST_V 7
#define SD_CS 10
#define REBOIL_SP 95.0f
#define COND_SP 80.0f
#define LOG_INTERVAL 5000UL
#define REFLUX_PERIOD 30000UL
#define N_PROBES 6
OneWire ow(OW_PIN); DallasTemperature ds(&ow); File lg;
float g_R=3.0f;
void distillation_reflux_controller(float R,unsigned long period,int rv,int dv){
  unsigned long tr=(unsigned long)(R/(R+1.0f)*period);
  unsigned long td=period-tr;
  digitalWrite(rv,HIGH);digitalWrite(dv,LOW);delay(tr);
  digitalWrite(rv,LOW);digitalWrite(dv,HIGH);delay(td);
  digitalWrite(dv,LOW);
}
void initHardware(){
  ds.begin();pinMode(SSR_PIN,OUTPUT);pinMode(REFLUX_V,OUTPUT);pinMode(DIST_V,OUTPUT);
  SD.begin(SD_CS);lg=SD.open("col.csv",FILE_WRITE);
  if(lg)lg.println("t_s,T0,T1,T2,T3,T4,T5,R,SSR");
  Serial.begin(9600);
}
void readColumnProfile(float*T){
  ds.requestTemperatures();
  for(int i=0;i<N_PROBES;i++) T[i]=ds.getTempCByIndex(i);
}
void reboilerSSRControl(float T){
  digitalWrite(SSR_PIN,(T<REBOIL_SP)?HIGH:LOW);
}
float adaptRefluxRatio(float T_cond, float R_cur){
  if(T_cond>COND_SP+1.0f) return min(R_cur+0.5f,8.0f);
  if(T_cond<COND_SP-2.0f) return max(R_cur-0.5f,2.0f);
  return R_cur;
}
void logDataSD(unsigned long t,float*T,float R,int ssr){
  if(lg){lg.print(t);
  for(int i=0;i<N_PROBES;i++){lg.print(',');lg.print(T[i],2);}
  lg.print(',');lg.print(R,2);lg.print(',');lg.println(ssr);lg.flush();}
}
void checkFaultSafety(float T_reb){
  if(T_reb>102.0f){digitalWrite(SSR_PIN,LOW);digitalWrite(REFLUX_V,LOW);digitalWrite(DIST_V,LOW);Serial.println("FAULT:REBOILER_OT");while(1);}
}
void setup(){initHardware();}
void loop(){
  static unsigned long prev=0;unsigned long now=millis();
  if(now-prev<LOG_INTERVAL)return;prev=now;
  float T[N_PROBES]; readColumnProfile(T);
  checkFaultSafety(T[0]);
  reboilerSSRControl(T[0]);
  g_R=adaptRefluxRatio(T[N_PROBES-1],g_R);
  int ssr=digitalRead(SSR_PIN);
  logDataSD(now/1000,T,g_R,ssr);
  Serial.print("Treb=");Serial.print(T[0],1);Serial.print(" Tcond=");Serial.print(T[5],1);Serial.print(" R=");Serial.println(g_R,2);
  distillation_reflux_controller(g_R,REFLUX_PERIOD,REFLUX_V,DIST_V);
}
